from urllib.request import Request, urlopen
from html.parser import HTMLParser
import re, json

class TextExtractor(HTMLParser):
    def __init__(self):
        super().__init__()
        self.text=[]
    def handle_data(self,data):
        t=data.strip()
        if t:
            self.text.append(t)

def fetch(url):
    req=Request(url, headers={'User-Agent':'Mozilla/5.0'})
    with urlopen(req, timeout=30) as r:
        return r.read().decode('utf-8','ignore')

for url in [
 'https://www.fubo.tv/about/leadership',
 'https://investors.fubo.tv/governance/management-team/default.aspx',
 'https://investors.fubo.tv/governance/board-of-directors/default.aspx',
 'https://www.fubo.tv/news'
]:
    try:
        html=fetch(url)
        print('\nURL',url,'len',len(html))
        p=TextExtractor(); p.feed(html)
        txt=' '.join(p.text)
        print(txt[:2500])
        m=re.findall(r'joined (?:the company|fubo(?:tv)?)[^.,;]* in (\d{4})', txt, re.I)
        if m: print('JOINYEARS',m[:20])
    except Exception as e:
        print('ERR',url,e)
PY","timeout_secs":60}

