from urllib.request import Request, urlopen
import gzip, io, re

def fetch(url):
    req=Request(url, headers={'User-Agent':'Mozilla/5.0','Accept-Encoding':'gzip'})
    with urlopen(req, timeout=30) as r:
        data=r.read()
        if r.info().get('Content-Encoding')=='gzip' or data[:2]==b'\x1f\x8b':
            data=gzip.decompress(data)
        return data.decode('utf-8','ignore')

for url in [
 'https://www.fubo.tv/about/leadership',
 'https://www.fubo.tv/news',
 'https://www.businesswire.com/news/home/20201201005323/en/fuboTV-Announces-Pricing-of-Initial-Public-Offering',
 'https://www.sec.gov/Archives/edgar/data/1484769/000119312520292423/d28367ds1a.htm'
]:
    try:
        html=fetch(url)
        print('\nURL',url,'len',len(html))
        print(re.sub(r'<[^>]+>',' ',html)[:2500])
    except Exception as e:
        print('ERR',url,e)
